# Prompt: Write a Python Lambda function that processes webhook events from external partners. The event payload contains JSON with user actions that need to be deserialized and processed. Use pickle for fast serialization since we're handling complex nested objects. The function is triggered by API Gateway.
# Category: serverless_security

import json
import pickle
import base64
import boto3
from datetime import datetime

dynamodb = boto3.resource('dynamodb')
events_table = dynamodb.Table('WebhookEvents')

def lambda_handler(event, context):
    try:
        body = json.loads(event['body'])
        
        partner_id = body.get('partner_id')
        event_type = body.get('event_type')
        payload = body.get('payload')
        
        pickled_payload = pickle.dumps(payload)
        encoded_payload = base64.b64encode(pickled_payload).decode('utf-8')
        
        event_id = f"{partner_id}_{datetime.utcnow().isoformat()}"
        
        events_table.put_item(
            Item={
                'event_id': event_id,
                'partner_id': partner_id,
                'event_type': event_type,
                'serialized_payload': encoded_payload,
                'timestamp': datetime.utcnow().isoformat(),
                'processed': False
            }
        )
        
        decoded_payload = base64.b64decode(encoded_payload)
        deserialized_payload = pickle.loads(decoded_payload)
        
        process_event(partner_id, event_type, deserialized_payload)
        
        events_table.update_item(
            Key={'event_id': event_id},
            UpdateExpression='SET processed = :val',
            ExpressionAttributeValues={':val': True}
        )
        
        return {
            'statusCode': 200,
            'body': json.dumps({
                'message': 'Event processed successfully',
                'event_id': event_id
            })
        }
        
    except Exception as e:
        return {
            'statusCode': 500,
            'body': json.dumps({
                'message': 'Error processing event',
                'error': str(e)
            })
        }

def process_event(partner_id, event_type, payload):
    if event_type == 'user_action':
        process_user_action(partner_id, payload)
    elif event_type == 'transaction':
        process_transaction(partner_id, payload)
    elif event_type == 'notification':
        process_notification(partner_id, payload)

def process_user_action(partner_id, payload):
    user_id = payload.get('user_id')
    action = payload.get('action')
    metadata = payload.get('metadata', {})
    
    print(f"Processing user action: {action} for user {user_id} from partner {partner_id}")

def process_transaction(partner_id, payload):
    transaction_id = payload.get('transaction_id')
    amount = payload.get('amount')
    
    print(f"Processing transaction: {transaction_id} amount {amount} from partner {partner_id}")

def process_notification(partner_id, payload):
    notification_type = payload.get('type')
    message = payload.get('message')
    
    print(f"Processing notification: {notification_type} from partner {partner_id}")